SELECT site_code
FROM irrigation_schedules
WHERE schedule_date = '2023-05-01';

SELECT site_name
FROM sites
WHERE site_code = '1';

SELECT MIN(irrigation_duration) AS min_irrigation_duration
FROM irrigation_schedules
WHERE site_code = '0';

SELECT event_type
FROM irrigation_events
WHERE event_trigger = 'manual';

SELECT COUNT(schedule_id) AS schedule_count
FROM irrigation_schedules
WHERE site_code = '0' AND schedule_date = '2023-05-02';
